// FACTORY
// ═══════════════════════════════════════════════════════════════════════

/**
 * Create a NeuralMesh from a model config.
 *
 * @example
 * ```ts
 * const mesh = createNeuralMesh({
 *   hiddenDim: 2048, numHeads: 32, numKvHeads: 4,
 *   headDim: 64, intermediateSize: 5632, numLayers: 22,
 * });
 * mesh.loadAllWeights(weights);
 * const output = mesh.forward(inputHidden, position);
 * ```
 */
export function createNeuralMesh(config: NeuralMeshModelConfig): NeuralMesh {
  return new NeuralMesh(config);
}

/**
 * Create a NeuralMesh auto-scaled to a parameter count.
 * Uses resolveSyzygyDimension to pick the appropriate gnostic level.
 */
export function createNeuralMeshForParameters(
  config: NeuralMeshModelConfig,
): NeuralMesh {
  // The mesh is always Sophia (k=3, s=3, β₁=9) because that's the
  // natural match for transformer weight tensor count.
  // The gnostic level determines the inter-mesh composition dimension
  // when multiple NeuralMeshes compose (future: model ensemble).
  return new NeuralMesh(config);
}

/**
 * Create random weights for testing.
 * Produces normally-distributed weights scaled by 1/√dim.
 */
export function createRandomCellWeights(
  config: NeuralMeshModelConfig,
): CellWeights {
  const { hiddenDim, numHeads, numKvHeads, headDim, intermediateSize } = config;
  const qDim = numHeads * headDim;
  const kvDim = numKvHeads * headDim;

  const randNorm = (size: number, scale: number): Float32Array => {
    const arr = new Float32Array(size);
    for (let i = 0; i < size; i++) {
      const u1 = Math.random();
      const u2 = Math.random();
      arr[i] = Math.sqrt(-2 * Math.log(u1)) * Math.cos(2 * Math.PI * u2) * scale;
    }
    return arr;
  };

  return {
    attnNorm: new Float32Array(hiddenDim).fill(1),
    qProj: randNorm(qDim * hiddenDim, 1 / Math.sqrt(hiddenDim)),
    ffnNorm: new Float32Array(hiddenDim).fill(1),
    kProj: randNorm(kvDim * hiddenDim, 1 / Math.sqrt(hiddenDim)),
    vProj: randNorm(kvDim * hiddenDim, 1 / Math.sqrt(hiddenDim)),
    gateProj: randNorm(intermediateSize * hiddenDim, 1 / Math.sqrt(hiddenDim)),
    oProj: randNorm(hiddenDim * qDim, 1 / Math.sqrt(qDim)),
    upProj: randNorm(intermediateSize * hiddenDim, 1 / Math.sqrt(hiddenDim)),
    downProj: randNorm(hiddenDim * intermediateSize, 1 / Math.sqrt(intermediateSize)),
  };
}
